 // InitTestSuite manages E2E tests for the init command
 type InitTestSuite struct {
-	t       *testing.T
-	logger  *TestLogger
-	tempDir string
-	cleanup []func()
+	t           *testing.T
+	logger      *TestLogger
+	tempDir     string
