+	if string(got) != string(paletteSentinel) {
+		suite.logger.Log("[E2E] FAIL: %s - expected palette preserved, got different content", t.Name())
+		t.Fatal("[E2E-INIT] Expected existing palette.md content to be preserved")
+	}
+}
